import {
    useEffect,
    useState
} from "react";


function UserDashboard() {

    const [complaints, setComplaints] =
        useState([]);

    const [filteredComplaints,
        setFilteredComplaints] =
        useState([]);

    const username =
        localStorage.getItem("username");


    useEffect(() => {

        fetch(
            "http://127.0.0.1:8000/complaints"
        )
        .then(res => res.json())
        .then(data => {

            setComplaints(data);

            setFilteredComplaints(data);
        });

    }, []);


    // Counts
    const openCount =
        complaints.filter(
            c => c.status === "Open"
        ).length;


    const closedCount =
        complaints.filter(
            c => c.status === "Closed"
        ).length;


    // Filter functions
    const showOpenComplaints = () => {

        const filtered =
            complaints.filter(
                c => c.status === "Open"
            );

        setFilteredComplaints(filtered);
    };


    const showClosedComplaints = () => {

        const filtered =
            complaints.filter(
                c => c.status === "Closed"
            );

        setFilteredComplaints(filtered);
    };


    const showAllComplaints = () => {

        setFilteredComplaints(complaints);
    };


    return (

        <div style={{ padding: "30px" }}>

            <h1>User Dashboard</h1>

            <h3>

                Welcome {username}

            </h3>

            <hr />

            <h2>Complaint Summary</h2>

            <button
                onClick={showOpenComplaints}
            >

                Open Complaints:
                {openCount}

            </button>

            <br /><br />

            <button
                onClick={showClosedComplaints}
            >

                Closed Complaints:
                {closedCount}

            </button>

            <br /><br />

            <button
                onClick={showAllComplaints}
            >

                Show All

            </button>

            <hr />

            <h2>Complaints</h2>

            {
                filteredComplaints.map((c) => (

                    <div
                        key={c.id}
                        style={{
                            border: "1px solid black",
                            padding: "10px",
                            marginBottom: "10px"
                        }}
                    >

                        <h3>

                            {c.title}

                        </h3>

                        <p>

                            {c.description}

                        </p>

                        <p>

                            Status:
                            {c.status}

                        </p>

                    </div>
                ))
            }

        </div>
    );
}

export default UserDashboard;
